     1в†’# Backend Development Guidelines
     2в†’
     3в†’**Purpose:** Enforce Node.js/TypeScript/Express patterns for ShadowTagAi backend services
     4в†’**Enforcement:** `"suggest"`
     5в†’**Priority:** `"high"`
     6в†’**Version:** 1.0.0
     7в†’
     8в†’---
     9в†’
    10в†’## Overview
    11в†’
    12в†’This skill provides best practices for building scalable, maintainable backend services using ShadowTagAi's tech stack. It covers architecture patterns, error handling, testing, and deployment practices.
    13в†’
    14в†’**Tech Stack:**
    15в†’- **Runtime:** Node.js 20+ with TypeScript 5+
    16в†’- **Framework:** Express.js with async/await
    17в†’- **Database:** PostgreSQL with Prisma ORM
    18в†’- **Package Manager:** pnpm (not npm/yarn)
    19в†’- **Process Manager:** PM2 for microservices
    20в†’- **Testing:** Jest with в‰Ґ98% coverage requirement
    21в†’- **Monitoring:** Sentry for error tracking
    22в†’
    23в†’---
    24в†’
    25в†’## Architecture Pattern
    26в†’
    27в†’### Layered Architecture (Standard)
    28в†’
    29в†’```
    30в†’Routes в†’ Controllers в†’ Services в†’ Repositories в†’ Database
    31в†’
    32в†’Example file structure:
    33в†’backend/
    34в†’в”њв”Ђв”Ђ src/
    35в†’в”‚   в”њв”Ђв”Ђ routes/          # API endpoint definitions
    36в†’в”‚   в”‚   в””в”Ђв”Ђ user.routes.ts
    37в†’в”‚   в”њв”Ђв”Ђ controllers/     # Request/response handling
    38в†’в”‚   в”‚   в””в”Ђв”Ђ user.controller.ts
    39в†’в”‚   в”њв”Ђв”Ђ services/        # Business logic
    40в†’в”‚   в”‚   в””в”Ђв”Ђ user.service.ts
    41в†’в”‚   в”њв”Ђв”Ђ repositories/    # Data access layer
    42в†’в”‚   в”‚   в””в”Ђв”Ђ user.repository.ts
    43в†’в”‚   в”њв”Ђв”Ђ models/          # TypeScript interfaces
    44в†’в”‚   в”‚   в””в”Ђв”Ђ user.model.ts
    45в†’в”‚   в”њв”Ђв”Ђ middleware/      # Express middleware
    46в†’в”‚   в”‚   в””в”Ђв”Ђ auth.middleware.ts
    47в†’в”‚   в””в”Ђв”Ђ utils/           # Helper functions
    48в†’в”‚       в””в”Ђв”Ђ crypto.util.ts
    49в†’в”њв”Ђв”Ђ prisma/
    50в†’в”‚   в””в”Ђв”Ђ schema.prisma    # Database schema
    51в†’в”њв”Ђв”Ђ tests/
    52в†’в”‚   в”њв”Ђв”Ђ unit/
    53в†’в”‚   в””в”Ђв”Ђ integration/
    54в†’в”њв”Ђв”Ђ package.json
    55в†’в””в”Ђв”Ђ tsconfig.json
    56в†’```
    57в†’
    58в†’---
    59в†’
    60в†’## Code Examples
    61в†’
    62в†’### 1. Route Definition
    63в†’
    64в†’```typescript
    65в†’// src/routes/user.routes.ts
    66в†’import { Router } from 'express';
    67в†’import { UserController } from '../controllers/user.controller';
    68в†’import { authenticate } from '../middleware/auth.middleware';
    69в†’import { validateRequest } from '../middleware/validation.middleware';
    70в†’import { createUserSchema } from '../schemas/user.schema';
    71в†’
    72в†’const router = Router();
    73в†’const userController = new UserController();
    74в†’
    75в†’// Public routes
    76в†’router.post(
    77в†’  '/register',
    78в†’  validateRequest(createUserSchema),
    79в†’  userController.register
    80в†’);
    81в†’
    82в†’// Protected routes
    83в†’router.get(
    84в†’  '/profile',
    85в†’  authenticate,
    86в†’  userController.getProfile
    87в†’);
    88в†’
    89в†’router.put(
    90в†’  '/profile',
    91в†’  authenticate,
    92в†’  validateRequest(updateUserSchema),
    93в†’  userController.updateProfile
    94в†’);
    95в†’
    96в†’export default router;
    97в†’```
    98в†’
    99в†’### 2. Controller (Request/Response Handling)
   100в†’
   101в†’```typescript
   102в†’// src/controllers/user.controller.ts
   103в†’import { Request, Response, NextFunction } from 'express';
   104в†’import { UserService } from '../services/user.service';
   105в†’import * as Sentry from '@sentry/node';
   106в†’
   107в†’export class UserController {
   108в†’  private userService: UserService;
   109в†’
   110в†’  constructor() {
   111в†’    this.userService = new UserService();
   112в†’  }
   113в†’
   114в†’  register = async (req: Request, res: Response, next: NextFunction): Promise<void> => {
   115в†’    try {
   116в†’      const { email, password, name } = req.body;
   117в†’
   118в†’      // Delegate business logic to service
   119в†’      const user = await this.userService.createUser({ email, password, name });
   120в†’
   121в†’      res.status(201).json({
   122в†’        success: true,
   123в†’        data: {
   124в†’          id: user.id,
   125в†’          email: user.email,
   126в†’          name: user.name
   127в†’        }
   128в†’      });
   129в†’    } catch (error) {
   130в†’      Sentry.captureException(error, {
   131в†’        tags: { controller: 'UserController', action: 'register' }
   132в†’      });
   133в†’      next(error); // Pass to error middleware
   134в†’    }
   135в†’  };
   136в†’
   137в†’  getProfile = async (req: Request, res: Response, next: NextFunction): Promise<void> => {
   138в†’    try {
   139в†’      const userId = req.user!.id; // Set by authenticate middleware
   140в†’
   141в†’      const user = await this.userService.getUserById(userId);
   142в†’
   143в†’      if (!user) {
   144в†’        return res.status(404).json({
   145в†’          success: false,
   146в†’          error: 'User not found'
   147в†’        });
   148в†’      }
   149в†’
   150в†’      res.status(200).json({
   151в†’        success: true,
   152в†’        data: user
   153в†’      });
   154в†’    } catch (error) {
   155в†’      Sentry.captureException(error, {
   156в†’        tags: { controller: 'UserController', action: 'getProfile' }
   157в†’      });
   158в†’      next(error);
   159в†’    }
   160в†’  };
   161в†’}
   162в†’```
   163в†’
   164в†’### 3. Service (Business Logic)
   165в†’
   166в†’```typescript
   167в†’// src/services/user.service.ts
   168в†’import { UserRepository } from '../repositories/user.repository';
   169в†’import { hashPassword, verifyPassword } from '../utils/crypto.util';
   170в†’import { CreateUserDTO, User } from '../models/user.model';
   171в†’
   172в†’export class UserService {
   173в†’  private userRepository: UserRepository;
   174в†’
   175в†’  constructor() {
   176в†’    this.userRepository = new UserRepository();
   177в†’  }
   178в†’
   179в†’  async createUser(data: CreateUserDTO): Promise<User> {
   180в†’    // Validate business rules
   181в†’    const existingUser = await this.userRepository.findByEmail(data.email);
   182в†’    if (existingUser) {
   183в†’      throw new Error('Email already registered');
   184в†’    }
   185в†’
   186в†’    // Hash password (using Argon2id - see security-enforcement skill)
   187в†’    const hashedPassword = await hashPassword(data.password);
   188в†’
   189в†’    // Delegate data persistence to repository
   190в†’    const user = await this.userRepository.create({
   191в†’      ...data,
   192в†’      password: hashedPassword
   193в†’    });
   194в†’
   195в†’    return user;
   196в†’  }
   197в†’
   198в†’  async getUserById(id: string): Promise<User | null> {
   199в†’    return this.userRepository.findById(id);
   200в†’  }
   201в†’
   202в†’  async authenticateUser(email: string, password: string): Promise<User> {
   203в†’    const user = await this.userRepository.findByEmail(email);
   204в†’
   205в†’    if (!user) {
   206в†’      throw new Error('Invalid credentials');
   207в†’    }
   208в†’
   209в†’    const isValidPassword = await verifyPassword(password, user.password);
   210в†’
   211в†’    if (!isValidPassword) {
   212в†’      throw new Error('Invalid credentials');
   213в†’    }
   214в†’
   215в†’    return user;
   216в†’  }
   217в†’}
   218в†’```
   219в†’
   220в†’### 4. Repository (Data Access)
   221в†’
   222в†’```typescript
   223в†’// src/repositories/user.repository.ts
   224в†’import { PrismaClient } from '@prisma/client';
   225в†’import { User, CreateUserDTO } from '../models/user.model';
   226в†’
   227в†’export class UserRepository {
   228в†’  private prisma: PrismaClient;
   229в†’
   230в†’  constructor() {
   231в†’    this.prisma = new PrismaClient();
   232в†’  }
   233в†’
   234в†’  async create(data: CreateUserDTO): Promise<User> {
   235в†’    return this.prisma.user.create({
   236в†’      data: {
   237в†’        email: data.email,
   238в†’        password: data.password,
   239в†’        name: data.name
   240в†’      }
   241в†’    });
   242в†’  }
   243в†’
   244в†’  async findById(id: string): Promise<User | null> {
   245в†’    return this.prisma.user.findUnique({
   246в†’      where: { id }
   247в†’    });
   248в†’  }
   249в†’
   250в†’  async findByEmail(email: string): Promise<User | null> {
   251в†’    return this.prisma.user.findUnique({
   252в†’      where: { email }
   253в†’    });
   254в†’  }
   255в†’
   256в†’  async update(id: string, data: Partial<User>): Promise<User> {
   257в†’    return this.prisma.user.update({
   258в†’      where: { id },
   259в†’      data
   260в†’    });
   261в†’  }
   262в†’
   263в†’  async delete(id: string): Promise<void> {
   264в†’    await this.prisma.user.delete({
   265в†’      where: { id }
   266в†’    });
   267в†’  }
   268в†’}
   269в†’```
