   273в†’## Error Handling
   274в†’
   275в†’### Global Error Middleware
   276в†’
   277в†’```typescript
   278в†’// src/middleware/error.middleware.ts
   279в†’import { Request, Response, NextFunction } from 'express';
   280в†’import * as Sentry from '@sentry/node';
   281в†’
   282в†’export class AppError extends Error {
   283в†’  statusCode: number;
   284в†’  isOperational: boolean;
   285в†’
   286в†’  constructor(message: string, statusCode: number = 500) {
   287в†’    super(message);
   288в†’    this.statusCode = statusCode;
   289в†’    this.isOperational = true;
   290в†’
   291в†’    Error.captureStackTrace(this, this.constructor);
   292в†’  }
   293в†’}
   294в†’
   295в†’export const errorHandler = (
   296в†’  error: Error | AppError,
   297в†’  req: Request,
   298в†’  res: Response,
   299в†’  next: NextFunction
   300в†’): void => {
   301в†’  let statusCode = 500;
   302в†’  let message = 'Internal server error';
   303в†’
   304в†’  if (error instanceof AppError) {
   305в†’    statusCode = error.statusCode;
   306в†’    message = error.message;
   307в†’  }
   308в†’
   309в†’  // Log to Sentry (all errors)
   310в†’  Sentry.captureException(error, {
   311в†’    tags: {
   312в†’      path: req.path,
   313в†’      method: req.method
   314в†’    },
   315в†’    extra: {
   316в†’      body: req.body,
   317в†’      query: req.query,
   318в†’      params: req.params
   319в†’    }
   320в†’  });
   321в†’
   322в†’  // Don't leak error details in production
   323в†’  const isDevelopment = process.env.NODE_ENV === 'development';
   324в†’
   325в†’  res.status(statusCode).json({
   326в†’    success: false,
   327в†’    error: message,
   328в†’    ...(isDevelopment && { stack: error.stack })
   329в†’  });
   330в†’};
   331в†’
   332в†’// Usage in app.ts
   333в†’app.use(errorHandler);
   334в†’```
