   351в†’  let mockUserRepository: jest.Mocked<UserRepository>;
   352в†’
   353в†’  beforeEach(() => {
   354в†’    mockUserRepository = new UserRepository() as jest.Mocked<UserRepository>;
   355в†’    userService = new UserService();
   356в†’    (userService as any).userRepository = mockUserRepository;
   357в†’  });
   358в†’
   359в†’  describe('createUser', () => {
   360в†’    it('should create a new user with hashed password', async () => {
   361в†’      const createUserDTO = {
   362в†’        email: 'test@example.com',
   363в†’        password: 'SecurePass123!',
   364в†’        name: 'Test User'
   365в†’      };
   366в†’
   367в†’      mockUserRepository.findByEmail.mockResolvedValue(null);
   368в†’      mockUserRepository.create.mockResolvedValue({
   369в†’        id: '123',
   370в†’        email: createUserDTO.email,
   371в†’        name: createUserDTO.name,
   372в†’        password: 'hashed-password',
   373в†’        createdAt: new Date()
   374в†’      });
   375в†’
   376в†’      const result = await userService.createUser(createUserDTO);
   377в†’
   378в†’      expect(result.email).toBe(createUserDTO.email);
   379в†’      expect(mockUserRepository.create).toHaveBeenCalledWith(
   380в†’        expect.objectContaining({
