   382в†’          name: createUserDTO.name,
   383в†’          password: expect.not.stringContaining('SecurePass123!')
   384в†’        })
   385в†’      );
   386в†’    });
   387в†’
   388в†’    it('should throw error if email already exists', async () => {
   389в†’      const createUserDTO = {
   390в†’        email: 'existing@example.com',
   391в†’        password: 'SecurePass123!',
   392в†’        name: 'Test User'
   393в†’      };
   394в†’
   395в†’      mockUserRepository.findByEmail.mockResolvedValue({
   396в†’        id: '456',
   397в†’        email: createUserDTO.email,
   398в†’        name: 'Existing User',
   399в†’        password: 'hashed',
