# Backend Development Guidelines

**Purpose:** Enforce Node.js/TypeScript/Express patterns for ShadowTagAi backend services
**Enforcement:** `"suggest"`
**Priority:** `"high"`
**Version:** 1.0.0

---

## Overview

This skill provides best practices for building scalable, maintainable backend services using ShadowTagAi's tech stack. It covers architecture patterns, error handling, testing, and deployment practices.

**Tech Stack:**
- **Runtime:** Node.js 20+ with TypeScript 5+
- **Framework:** Express.js with async/await
- **Database:** PostgreSQL with Prisma ORM
- **Package Manager:** pnpm (not npm/yarn)
- **Process Manager:** PM2 for microservices
- **Testing:** Jest with в‰Ґ98% coverage requirement
- **Monitoring:** Sentry for error tracking

---

## Architecture Pattern

### Layered Architecture (Standard)

```
Routes в†’ Controllers в†’ Services в†’ Repositories в†’ Database

Example file structure:
backend/
в”њв”Ђв”Ђ src/
в”‚   в”њв”Ђв”Ђ routes/          # API endpoint definitions
в”‚   в”‚   в””в”Ђв”Ђ user.routes.ts
в”‚   в”њв”Ђв”Ђ controllers/     # Request/response handling
в”‚   в”‚   в””в”Ђв”Ђ user.controller.ts
в”‚   в”њв”Ђв”Ђ services/        # Business logic
в”‚   в”‚   в””в”Ђв”Ђ user.service.ts
в”‚   в”њв”Ђв”Ђ repositories/    # Data access layer
в”‚   в”‚   в””в”Ђв”Ђ user.repository.ts
в”‚   в”њв”Ђв”Ђ models/          # TypeScript interfaces
в”‚   в”‚   в””в”Ђв”Ђ user.model.ts
в”‚   в”њв”Ђв”Ђ middleware/      # Express middleware
в”‚   в”‚   в””в”Ђв”Ђ auth.middleware.ts
в”‚   в””в”Ђв”Ђ utils/           # Helper functions
в”‚       в””в”Ђв”Ђ crypto.util.ts
в”њв”Ђв”Ђ prisma/
в”‚   в””в”Ђв”Ђ schema.prisma    # Database schema
в”њв”Ђв”Ђ tests/
в”‚   в”њв”Ђв”Ђ unit/
в”‚   в””в”Ђв”Ђ integration/
в”њв”Ђв”Ђ package.json
в””в”Ђв”Ђ tsconfig.json
```

---

## Code Examples

### 1. Route Definition

```typescript
// src/routes/user.routes.ts
import { Router } from 'express';
import { UserController } from '../controllers/user.controller';
import { authenticate } from '../middleware/auth.middleware';
import { validateRequest } from '../middleware/validation.middleware';
import { createUserSchema } from '../schemas/user.schema';

const router = Router();
const userController = new UserController();

// Public routes
router.post(
  '/register',
  validateRequest(createUserSchema),
  userController.register
);

// Protected routes
router.get(
  '/profile',
  authenticate,
  userController.getProfile
);

router.put(
  '/profile',
  authenticate,
  validateRequest(updateUserSchema),
  userController.updateProfile
);

export default router;
```

### 2. Controller (Request/Response Handling)

```typescript
// src/controllers/user.controller.ts
import { Request, Response, NextFunction } from 'express';
import { UserService } from '../services/user.service';
import * as Sentry from '@sentry/node';

export class UserController {
  private userService: UserService;

  constructor() {
    this.userService = new UserService();
  }

  register = async (req: Request, res: Response, next: NextFunction): Promise<void> => {
    try {
      const { email, password, name } = req.body;

      // Delegate business logic to service
      const user = await this.userService.createUser({ email, password, name });

      res.status(201).json({
        success: true,
        data: {
          id: user.id,
          email: user.email,
          name: user.name
        }
      });
    } catch (error) {
      Sentry.captureException(error, {
        tags: { controller: 'UserController', action: 'register' }
      });
      next(error); // Pass to error middleware
    }
  };

  getProfile = async (req: Request, res: Response, next: NextFunction): Promise<void> => {
    try {
      const userId = req.user!.id; // Set by authenticate middleware

      const user = await this.userService.getUserById(userId);

      if (!user) {
        return res.status(404).json({
          success: false,
          error: 'User not found'
        });
      }

      res.status(200).json({
        success: true,
        data: user
      });
    } catch (error) {
      Sentry.captureException(error, {
        tags: { controller: 'UserController', action: 'getProfile' }
      });
      next(error);
    }
  };
}
```

### 3. Service (Business Logic)

```typescript
// src/services/user.service.ts
import { UserRepository } from '../repositories/user.repository';
import { hashPassword, verifyPassword } from '../utils/crypto.util';
import { CreateUserDTO, User } from '../models/user.model';

export class UserService {
  private userRepository: UserRepository;

  constructor() {
    this.userRepository = new UserRepository();
  }

  async createUser(data: CreateUserDTO): Promise<User> {
    // Validate business rules
    const existingUser = await this.userRepository.findByEmail(data.email);
    if (existingUser) {
      throw new Error('Email already registered');
    }

    // Hash password (using Argon2id - see security-enforcement skill)
    const hashedPassword = await hashPassword(data.password);

    // Delegate data persistence to repository
    const user = await this.userRepository.create({
      ...data,
      password: hashedPassword
    });

    return user;
  }

  async getUserById(id: string): Promise<User | null> {
    return this.userRepository.findById(id);
  }

  async authenticateUser(email: string, password: string): Promise<User> {
    const user = await this.userRepository.findByEmail(email);

    if (!user) {
      throw new Error('Invalid credentials');
    }

    const isValidPassword = await verifyPassword(password, user.password);

    if (!isValidPassword) {
      throw new Error('Invalid credentials');
    }

    return user;
  }
}
```

### 4. Repository (Data Access)

```typescript
// src/repositories/user.repository.ts
import { PrismaClient } from '@prisma/client';
import { User, CreateUserDTO } from '../models/user.model';

export class UserRepository {
  private prisma: PrismaClient;

  constructor() {
    this.prisma = new PrismaClient();
  }

  async create(data: CreateUserDTO): Promise<User> {
    return this.prisma.user.create({
      data: {
        email: data.email,
        password: data.password,
        name: data.name
      }
    });
  }

  async findById(id: string): Promise<User | null> {
    return this.prisma.user.findUnique({
      where: { id }
    });
  }

  async findByEmail(email: string): Promise<User | null> {
    return this.prisma.user.findUnique({
      where: { email }
    });
  }

  async update(id: string, data: Partial<User>): Promise<User> {
    return this.prisma.user.update({
      where: { id },
      data
    });
  }

  async delete(id: string): Promise<void> {
    await this.prisma.user.delete({
      where: { id }
    });
  }
}
```

---

## Error Handling

### Global Error Middleware

```typescript
// src/middleware/error.middleware.ts
import { Request, Response, NextFunction } from 'express';
import * as Sentry from '@sentry/node';

export class AppError extends Error {
  statusCode: number;
  isOperational: boolean;

  constructor(message: string, statusCode: number = 500) {
    super(message);
    this.statusCode = statusCode;
    this.isOperational = true;

    Error.captureStackTrace(this, this.constructor);
  }
}

export const errorHandler = (
  error: Error | AppError,
  req: Request,
  res: Response,
  next: NextFunction
): void => {
  let statusCode = 500;
  let message = 'Internal server error';

  if (error instanceof AppError) {
    statusCode = error.statusCode;
    message = error.message;
  }

  // Log to Sentry (all errors)
  Sentry.captureException(error, {
    tags: {
      path: req.path,
      method: req.method
    },
    extra: {
      body: req.body,
      query: req.query,
      params: req.params
    }
  });

  // Don't leak error details in production
  const isDevelopment = process.env.NODE_ENV === 'development';

  res.status(statusCode).json({
    success: false,
    error: message,
    ...(isDevelopment && { stack: error.stack })
  });
};

// Usage in app.ts
app.use(errorHandler);
```

---

## Testing

### Unit Tests (Jest)

```typescript
// tests/unit/user.service.test.ts
import { UserService } from '../../src/services/user.service';
import { UserRepository } from '../../src/repositories/user.repository';

jest.mock('../../src/repositories/user.repository');

describe('UserService', () => {
  let userService: UserService;
  let mockUserRepository: jest.Mocked<UserRepository>;

  beforeEach(() => {
    mockUserRepository = new UserRepository() as jest.Mocked<UserRepository>;
    userService = new UserService();
    (userService as any).userRepository = mockUserRepository;
  });

  describe('createUser', () => {
    it('should create a new user with hashed password', async () => {
      const createUserDTO = {
        email: 'test@example.com',
        password: 'SecurePass123!',
        name: 'Test User'
      };

      mockUserRepository.findByEmail.mockResolvedValue(null);
      mockUserRepository.create.mockResolvedValue({
        id: '123',
        email: createUserDTO.email,
        name: createUserDTO.name,
        password: 'hashed-password',
        createdAt: new Date()
      });

      const result = await userService.createUser(createUserDTO);

      expect(result.email).toBe(createUserDTO.email);
      expect(mockUserRepository.create).toHaveBeenCalledWith(
        expect.objectContaining({
          email: createUserDTO.email,
          name: createUserDTO.name,
          password: expect.not.stringContaining('SecurePass123!')
        })
      );
    });

    it('should throw error if email already exists', async () => {
      const createUserDTO = {
        email: 'existing@example.com',
        password: 'SecurePass123!',
        name: 'Test User'
      };

      mockUserRepository.findByEmail.mockResolvedValue({
        id: '456',
        email: createUserDTO.email,
        name: 'Existing User',
        password: 'hashed',
        createdAt: new Date()
      });

      await expect(userService.createUser(createUserDTO)).rejects.toThrow(
        'Email already registered'
      );
    });
  });
});
```

### Integration Tests

```typescript
// tests/integration/user.routes.test.ts
import request from 'supertest';
import app from '../../src/app';
